// AI SUITE ORCHESTRATOR
// Routes requests to the right AI-powered service
const body = $input.first().json;
const service = body.service || 'auto';
const action = body.action || 'query';
const content = body.content || body.text || body.query || '';

// Service map
const services = {
  'search':   { url: 'http://localhost:8082/search', method: 'GET' },
  'pdf':      { url: 'http://localhost:8083/api/v1/convert', method: 'POST' },
  'sheets':   { url: 'http://localhost:8081/api/v1', method: 'POST' },
  'forms':    { url: 'http://localhost:8084/api', method: 'POST' },
  'ai':       { url: 'http://localhost:4000/chat/completions', method: 'POST' },
  'embed':    { url: 'http://localhost:4000/embeddings', method: 'POST' },
  'monitor':  { url: 'http://localhost:3001/api', method: 'GET' },
  'cloud':    { url: 'http://localhost:8080', method: 'GET' },
  'analytics':{ url: 'http://localhost:8085/api', method: 'GET' },
  'typesense':{ url: 'http://localhost:8108', method: 'GET' },
};

// Auto-route based on content
let targetService = service;
if (service === 'auto') {
  if (content.toLowerCase().includes('search') || content.includes('?')) targetService = 'search';
  else if (content.toLowerCase().includes('pdf')) targetService = 'pdf';
  else if (content.toLowerCase().includes('spreadsheet') || content.toLowerCase().includes('data')) targetService = 'sheets';
  else targetService = 'ai';
}

const target = services[targetService] || services['ai'];

return [{
  json: {
    service: targetService,
    action,
    content,
    target_url: target.url,
    target_method: target.method,
    routed_at: new Date().toISOString(),
    orchestrator: 'AI_SUITE_v1'
  }
}];
